B.aob=new A.bf(25,B.bs,"Make a Vanguard Pawn, then Make it Stick","Kurai wo tottara kurai no kakuho",B.a_x)
B.aiT=new A.c("People used to take this proverb quite seriously, and did the best they could to prevent the opponent from maintaining a 5e vanguard Pawn. But in present-day shogi, it does not always hold true.")
B.ai2=new A.c("Diagram 1 (last move K4a) shows where White has successfully realized the 5e vanguard Pawn. The position is supposed to be in favor of White according to the proverb, but not so in reality.")
B.Nm=new A.p("ln1g1k1nl/4r1gb1/p1pp1s1p1/4spp1p/4p4/P1P2PPRP/1P1PPSN2/1BKGSG3/LN6L b Pp","Diagram 1")
B.ahU=new A.c("See how Black's R,B,S,and N are ideally placed for an attack.")
