B.aot=new A.bf(30,B.de,"Against a Silver in front of its Pawn, defend with a Pawn","Fugoshi-gin niwa Fu de taikou",B.UO)
B.afl=new A.c("When you have several Pawns in hand, you will have more lines of attack to choose from. The above saying teaches that a combination of a joining Pawn and a dangling Pawn tesuji is most likely to work in your favor, if you have enough Pawns.")
B.NO=new A.p("7nl/6gk1/5ppp1/8p/9/6P1P/5P3/7R1/7NL b 3P","Diagram 1-1")
B.a4r=A.a(s(["P2d","Px2d","P*2e"]),t.s)
B.a8Q=new A.Q("Moves from Diagram 1-1:",B.a4r,B.j)
B.ag1=new A.c("Above is the joining Pawn tesuji.")
B.a2X=A.a(s(["Px2e","P*2d"]),t.s)
B.aa8=new A.Q("Moves thereafter:",B.a2X,B.u)
