B.aol=new A.bf(32,B.de,"Recapture the Vanguard with a Joining Pawn","Kurai no dakkai awase no tesuji",B.a28)
B.ajF=new A.c("This applies when you plan a quick attack against ranging Rook.")
B.MZ=new A.p(u.m,"Diagram 1-1")
B.aft=new A.c("Diagram 1-1 (last move S4c) is just an ordinary position you are likely to see when playing static Rook against ranging Rook. Just for the sake of argument, suppose both Bishops are in each other's hand instead of on board (Diagram 1-2).")
B.Of=new A.p("ln1g3nl/1ks1gr3/1pppps1pp/p4pp2/7P1/P1P1P1P2/1P1PSP2P/2K1GS1R1/LN1G3NL b Bb","Diagram 1-2")
B.afn=new A.c("From Diagram 1-2, the static Rook side has a very good move to play: P2d. This is why the ranging Rook side has to avoid Bishop-exchange. After Px2d, Rx2d, White may drop a Pawn on 2b for defense, but Black can drop his on 2c to get a favorable position.")
