B.aa7=new A.Q("From Diagram 2-1 (last move S4c) there will follow:",B.XD,B.j)
B.Mw=new A.p("ln1g3nl/1ks1gr3/1pp1psbpp/p2p1pp2/5P1P1/P1P1P1P2/1P1PS3P/1BK1GS1R1/LN1G3NL w -","Diagram 2-2")
B.adE=new A.c("After Black's P4e, if White responds with Px4e, Black will next play Bx3c+, followed by Nx3c, P2d, Px2d, Rx2d (Diagram 2-3), a favorable position for Black.")
B.KM=new A.p("ln1g4l/1ks1gr3/1pp1psn1p/p2p2pR1/5p3/P1P1P1P2/1P1PS3P/2K1GS3/LN1G3NL w BPb2p","Diagram 2-3")
B.akF=new A.c("Therefore, White cannot let that happen.")
