B.alT=new A.c("What if, instead of playing Px4e, White plans to get his King more breathing room by P7d? In this case, Black does not have to hurry: By N3g he can strengthen his attacking force an wait for the right time.")
B.a19=A.a(s(["P2d","Px2d","Px4d","Sx4d","P*4e","S5c","B3c+","Nx3c","Rx2d"]),t.s)
B.a8S=new A.Q("Moves after Diagram 2-4:",B.a19,B.j)
B.M5=new A.p("ln1g4l/1ks1gr3/1p2s1n1p/p1ppp1pR1/5P3/P1P1P1P2/1P1PS1N1P/2K1GS3/LN1G4L w BPb2p","Diagram 2-5")
B.adF=new A.c("Strictly speaking, the position is even in Diagram 2-5, but Black initiated the sequence of moves and now has the position exactly as he had planned. Black should have nothing to complain here.")
