B.amB=new A.c("Neither side takes the Pawn. Whichever takes it will only give the opponent momentum. Let the opponent take it, and your piece can move forward by taking it again.")
B.XH=A.a(s(["P7f","Sx7f","P6e"]),t.s)
B.a8O=new A.Q("Moves from Diagram 2-2:",B.XH,B.u)
B.La=new A.p("ln5nl/2r1ggkb1/p3sp1p1/1s2p1p1p/1p1p5/2SPPPP1P/PP5P1/L1R1GBSK1/1N3G1NL b Pp","Diagram 2-3")
B.aht=new A.c("So far we have seen one of the most popular variations of the bo-gin (climbing Silver) opening.")
B.afi=new A.c("Strictly speaking, the position here is even. But if Black can bring about the Rook-exchange, he will have much to hope for.")
