B.acR=new A.ar(B.Uv)
B.ait=new A.c("In Diagram 3-1, White has taken the diagonal climbing Silver (naname-bo-gin) in which his left Silver diagonally advanced from 4b to 5c to 6d. Compared with the standard bo-gin, the diagonal variation can save time: He can play P7e one move earlier than the original version. However, you should be careful because, when Black plays P6e to open his Bishop's path, it also claims the Silver on 6d.")
B.Lo=new A.p("ln3g1nl/1r1sg1kb1/p2p1p1p1/3sp1p1p/1pp6/2PPPP2P/PPBS2PP1/3RG1SK1/LN3G1NL b -","Diagram 3-1")
B.Yh=A.a(s(["R7h"]),t.s)
